import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Common Basic Courses","description":"Introduces the common basic courses offered at SCUT and links to related study materials","frontmatter":{"lang":"en-US","title":"Common Basic Courses","description":"Introduces the common basic courses offered at SCUT and links to related study materials","llm_translated":true},"headers":[],"relativePath":"en/learn/curricular/common_basic_lessons.md","filePath":"en/learn/curricular/common_basic_lessons.md","lastUpdated":1784829332000}`),a={name:`en/learn/curricular/common_basic_lessons.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/curricular/common_basic_lessons.md for this page in Markdown format</div><h1 id="common-basic-courses" tabindex="-1">Common Basic Courses <a class="header-anchor" href="#common-basic-courses" aria-label="Permalink to “Common Basic Courses”">​</a></h1><p>The common basic courses at SCUT (mainly taken in the first year) include mathematics, physics, electrical engineering, English, physical education, political education, and practice/internship/training courses. These include but are not limited to:</p><ul><li><strong>Mathematics</strong><ul><li>Advanced Mathematics (difficulty from low to high) <ul><li>Calculus Foundations (one semester)</li><li>Calculus I (Part 1/Part 2)</li><li>Calculus II (Part 1/Part 2) (Chemical Engineering track, Part 2 = 4 credits, no series)</li><li>Calculus II (Part 1/Part 2) (Non-chemical Engineering track, Part 2 = 5 credits, includes series)</li><li>Engineering Mathematical Analysis (Part 1/Part 2) (Computer Science, Software, Baibu Step, Information Engineering Innovation Class, Part 2 = 7 credits)</li><li>Mathematical Analysis (Part 1/Part 2) (School of Mathematics only)</li></ul></li><li>Linear Algebra and Analytic Geometry</li><li>Probability Theory and Mathematical Statistics</li><li>Complex Functions and Integral Transforms</li></ul></li><li><strong>English</strong><ul><li>Academic English (I)/(II) (can be exempted in semester 2 with IELTS/TOEFL scores)</li><li>College English (I)/(II)</li></ul></li><li><strong>Physics</strong><ul><li>University Physics (3 credits) Part 1/Part 2</li><li>University Physics (4 credits) Part 1/Part 2</li></ul></li><li><strong>Electrical Engineering</strong><ul><li>Electric Circuits</li><li>Electrical Engineering</li><li>Analog Electronics</li><li>Digital Electronics</li></ul></li><li><strong>Physical Education</strong><ul><li>Physical Fitness / PE I</li><li>PE II</li><li>PE III</li><li>PE IV</li><li>PE courses usually end after the second year</li></ul></li><li><strong>Political Education</strong><ul><li>Military Theory</li><li>Ideology, Morality, and Rule of Law</li><li>Introduction to Xi Jinping Thought on Socialism with Chinese Characteristics for a New Era</li><li>Introduction to Mao Zedong Thought</li><li>Outline of Modern Chinese History</li><li>College Student Mental Health</li><li>National Security Education</li><li>Four History Courses (choose one) <ul><li>History of the People&#39;s Republic of China</li><li>History of the Chinese Communist Party</li><li>History of Reform and Opening Up</li><li>History of Socialist Development</li></ul></li></ul></li><li><strong>Practice, Internship, and Training</strong> (each major takes some of the following, <strong>not all</strong>) <ul><li>University Physics Experiment</li><li>University Chemistry Experiment</li><li>Metalworking Practice</li><li>Electrical Engineering Practice</li><li>Marxist Practice</li><li>Military Skills (Military Training)</li></ul></li></ul><p>The above common basic course system covers the training plans for most domestic students in the <strong>Wushan Campus and University Town Campus</strong>. Courses for international students and students from Hong Kong, Macau, and Taiwan differ. Note that the common basic course system for students in <strong>GZIC (International Campus) programs</strong> differs from the above.</p><h2 id="mathematics" tabindex="-1">Mathematics <a class="header-anchor" href="#mathematics" aria-label="Permalink to “Mathematics”">​</a></h2><h3 id="advanced-mathematics" tabindex="-1">Advanced Mathematics <a class="header-anchor" href="#advanced-mathematics" aria-label="Permalink to “Advanced Mathematics”">​</a></h3><p>SCUT&#39;s mathematics courses are divided into four levels as described above, corresponding to the mathematical requirements of different majors, with varying difficulty and scope. Medical programs typically take <strong>Calculus Foundations</strong>, general engineering and science programs usually take <strong>Calculus I or II</strong>, and the <strong>School of Computer Science, School of Software, Baibu Step Innovation College</strong>, and some <strong>Engineering Innovation Classes</strong> require <strong>Engineering Mathematical Analysis</strong>.</p><p><strong>Study Materials and Tools</strong></p><ul><li>Advanced Mathematics Quick Reference (@Mike_Unknown): <a href="https://fastgit.cc/https://raw.githubusercontent.com/Kozmosa/survive-in-scut/main/assets/%E9%AB%98%E7%AD%89%E6%95%B0%E5%AD%A6%E9%80%9F%E6%9F%A5%E8%A1%A8.pdf" target="_blank" rel="noreferrer">Advanced Mathematics Quick Reference PDF</a></li></ul><h3 id="linear-algebra-and-analytic-geometry" tabindex="-1">Linear Algebra and Analytic Geometry <a class="header-anchor" href="#linear-algebra-and-analytic-geometry" aria-label="Permalink to “Linear Algebra and Analytic Geometry”">​</a></h3><p>This course is generally taken in the first semester.</p><p>TODO: Improve the course description and study materials for Linear Algebra:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Course content overview: systems of linear equations, matrix operations, vector spaces, eigenvalues and eigenvectors, and other core topics</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Recommended textbooks and references: Tongji edition “Linear Algebra” and companion exercise book</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Learning resources: recommended online courses (e.g., MIT 18.06 Linear Algebra), SCUT past exam papers and review notes</li></ul><h3 id="probability-theory-and-mathematical-statistics" tabindex="-1">Probability Theory and Mathematical Statistics <a class="header-anchor" href="#probability-theory-and-mathematical-statistics" aria-label="Permalink to “Probability Theory and Mathematical Statistics”">​</a></h3><p>This course is generally taken in the second semester by engineering and science majors.</p><p><strong>Study Materials</strong></p><ul><li>SCUT Probability Notes: <a href="./common/probalistics_and_statistics/plt_note">Probability Theory and Mathematical Statistics Handwritten Notes</a></li><li>Interactive Visualization Tool: <a href="./common/probalistics_and_statistics/distribution_gallery">Probability Distribution Gallery</a></li></ul><p>TODO: Improve the course description and study materials for Probability:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Course content overview: probability axioms, random variables, law of large numbers and central limit theorem, fundamentals of mathematical statistics</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Recommended textbooks and references: Zhejiang University edition “Probability Theory and Mathematical Statistics” and companion solutions</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Learning resources: recommended online courses, SCUT past exam papers and review notes</li></ul><h3 id="complex-functions-and-integral-transforms" tabindex="-1">Complex Functions and Integral Transforms <a class="header-anchor" href="#complex-functions-and-integral-transforms" aria-label="Permalink to “Complex Functions and Integral Transforms”">​</a></h3><p>This course is generally taken in the second semester by engineering and science majors.</p><p>TODO: Improve the course description and study materials for Complex Functions:</p><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Course content overview: complex numbers and complex functions, analytic functions, complex integration, series and residue theorem</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Recommended textbooks and references: Xi&#39;an Jiaotong University edition “Complex Functions” and companion exercise book</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Learning resources: recommended online courses, SCUT past exam papers and review notes</li></ul><h2 id="english" tabindex="-1">English <a class="header-anchor" href="#english" aria-label="Permalink to “English”">​</a></h2><h2 id="physics" tabindex="-1">Physics <a class="header-anchor" href="#physics" aria-label="Permalink to “Physics”">​</a></h2><h3 id="university-physics" tabindex="-1">University Physics <a class="header-anchor" href="#university-physics" aria-label="Permalink to “University Physics”">​</a></h3><p>Whether this course is offered depends on the school and major. Regular engineering and science classes generally start University Physics Part 1 in the second semester.</p><p><strong>Study Materials</strong></p><ul><li><em>Oplisty</em>&#39;s <strong>SCUT University Physics Review Notes</strong> (also applicable to the International Campus): <ul><li><a href="https://www.zhihu.com/column/c_1888956732467823738" target="_blank" rel="noreferrer">University Physics Theorem Summary Express Edition</a></li></ul></li></ul><h2 id="political-education" tabindex="-1">Political Education <a class="header-anchor" href="#political-education" aria-label="Permalink to “Political Education”">​</a></h2><h3 id="marxist-theory-and-practice" tabindex="-1">Marxist Theory and Practice <a class="header-anchor" href="#marxist-theory-and-practice" aria-label="Permalink to “Marxist Theory and Practice”">​</a></h3><p>This is a required political education course. Note: Due to curriculum adjustments, this guide does not evaluate the “Leading the Way” Guangdong Practice or the “Virtual Simulation” experiential teaching modules.</p><h4 id="elective-module-introduction-and-recommendations" tabindex="-1">Elective Module Introduction and Recommendations <a class="header-anchor" href="#elective-module-introduction-and-recommendations" aria-label="Permalink to “Elective Module Introduction and Recommendations”">​</a></h4><h4 id="_1-red-base-site-visits" tabindex="-1">1. “Red Base” Site Visits <a class="header-anchor" href="#_1-red-base-site-visits" aria-label="Permalink to “1. “Red Base” Site Visits”">​</a></h4><p><strong>Requirements:</strong></p><ul><li>Select one Red Base from each of three periods: the New Democratic Revolution (1919-1949), Socialist Revolution and Construction (1949-1978), and Reform and Opening Up (1978-2012). Visit each and take a group photo.</li><li>Write a reflection essay of no less than 2,500 characters.</li></ul><p><strong>Evaluation:</strong></p><ul><li><p>Advantages: This module is quite flexible. Practice locations are not limited to Guangzhou (where the university is located). Students can visit Red Bases across the country during their free time or holidays. If choosing to complete it in Guangzhou, the goal can be achieved efficiently within a single day.</p></li><li><p>Suggestions: When choosing bases outside Guangzhou, note that some bases may have ambiguous historical period classifications. Carefully verify before selecting sites. Additionally, since cross-regional practice topics are diverse, reports tend to be more original with lower plagiarism check rates, giving them a competitive edge in scoring.</p></li></ul><h4 id="_2-rural-china-social-survey" tabindex="-1">2. “Rural China” Social Survey <a class="header-anchor" href="#_2-rural-china-social-survey" aria-label="Permalink to “2. “Rural China” Social Survey”">​</a></h4><p><strong>Requirements:</strong></p><ul><li>Select an administrative village based on respondent-driven sampling (RDS) principles for on-site qualitative investigation, and obtain practice certification materials (such as receipts) as required.</li><li>Write one qualitative survey report of no less than 2,500 characters.</li></ul><p><strong>Evaluation:</strong></p><p>The core difficulty lies in sample selection and coordinating interviews with respondents (such as village officials and rural doctors). Since respondents must meet “true rural” standards (villages around campus like Beigang Village or Suishi Village, which have effectively become “urban villages,” are generally ineligible), the level of difficulty varies by individual.</p><h4 id="_3-love-spreads-across-guangzhou-volunteer-service" tabindex="-1">3. “Love Spreads Across Guangzhou” Volunteer Service <a class="header-anchor" href="#_3-love-spreads-across-guangzhou-volunteer-service" aria-label="Permalink to “3. “Love Spreads Across Guangzhou” Volunteer Service”">​</a></h4><p><strong>Requirements:</strong></p><ul><li>Complete no less than 15 hours of volunteer service in designated fields within Guangzhou city limits between July and November 2026.</li><li>Write one reflection essay of no less than 2,500 characters on the volunteer experience.</li></ul><p><strong>Evaluation:</strong></p><ul><li><p>Target audience: Students who still need volunteer hours for graduation requirements should consider this option, as the volunteer hours from this course can count toward graduation.</p></li><li><p>Pitfall warning: Students aiming for high GPAs should choose carefully. The grading criteria for this module are highly uncertain -- there is no strict linear positive correlation between volunteer hours and final GPA. Cases exist where “many hours but average GPA” occurs, as well as occasional instances of “few volunteer hours but high scores.” Essentially, scoring in this module is influenced by multiple subjective factors, and hours are not a decisive GPA indicator. Carefully weigh your time costs and GPA expectations.</p></li></ul><h4 id="_4-classic-works-study-and-presentation" tabindex="-1">4. “Classic Works” Study and Presentation <a class="header-anchor" href="#_4-classic-works-study-and-presentation" aria-label="Permalink to “4. “Classic Works” Study and Presentation”">​</a></h4><p><strong>Requirements:</strong> Form groups of 10 people, conduct group study sessions, and deliver at least one presentation on a classic work (including PPT creation and presentation).</p><p><strong>Evaluation:</strong> This module involves teamwork and in-depth theoretical discussion. Given the communication costs of group formation and the complexity of project collaboration, it is not recommended as a first choice.</p><h4 id="author-s-note" tabindex="-1">Author&#39;s Note <a class="header-anchor" href="#author-s-note" aria-label="Permalink to “Author&#39;s Note”">​</a></h4><h4 id="social-practice-credit-recognition-suggestion" tabindex="-1">Social Practice Credit Recognition Suggestion <a class="header-anchor" href="#social-practice-credit-recognition-suggestion" aria-label="Permalink to “Social Practice Credit Recognition Suggestion”">​</a></h4><p>If your school arranges social practice recognition at the start of the semester, the practical成果 from this required course can usually be applied once toward meeting graduation social practice requirements. Watch for school notices to maximize the utility of your practical achievements.</p><h4 id="volunteer-hour-guide-and-channel-suggestions" tabindex="-1">Volunteer Hour Guide and Channel Suggestions <a class="header-anchor" href="#volunteer-hour-guide-and-channel-suggestions" aria-label="Permalink to “Volunteer Hour Guide and Channel Suggestions”">​</a></h4><p>If you need volunteer hours for graduation, consider using the following official or正规 channels based on your interests and schedule. Note: <strong>Volunteer hours are only one evaluation reference -- do not blindly pursue hours at the expense of practice quality.</strong></p><ul><li><p><strong>Common Social Volunteer Channels</strong>:</p><ul><li><p><strong>Regular Service</strong>: Metro volunteers, library volunteers, various school/department official event recruitment. These activities are usually announced by class monitors.</p></li><li><p><strong>Special and Long-term Projects</strong>:</p><ul><li><p><strong>Blue Letter</strong>: Provides psychological companionship support through long-term correspondence with rural children. Each letter is typically recognized as 3 volunteer hours. Details at <a href="http://www.lanxinfeng.cn/" target="_blank" rel="noreferrer">Blue Letter Official Platform</a>.</p></li><li><p><strong>Three Trips to the Countryside / “Hundreds and Thousands of Projects”</strong>: Grassroots social practice projects. <strong>Important</strong>: Volunteer hour recognition for such activities is usually determined by the partner organization. Confirm volunteer hour requirements with the partner organization before participating.</p></li></ul></li><li><p><strong>Large Events and Social Recruitment</strong>: Volunteers for concerts, music festivals, and other large events. Register through official WeChat public accounts or mini-programs. Stay alert, verify information sources, and guard against scams.</p></li><li><p><strong>Winter Recruitment Volunteer</strong>: Divided into two paths: “University Distribution” and “High School Distribution.”</p><ul><li><p><strong>University Distribution</strong>: Usually requires selection to become a school team member, earning about 8-10 volunteer hours. Follow the <strong>鲤工小招招</strong> official account for details.</p></li><li><p><strong>High School Distribution</strong>: Hour recognition standards are determined by your high school. Communicate with the responsible teacher at your high school in advance.</p></li></ul></li></ul></li></ul>`,58)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};